// ============================================
// PARSE UNIFICADO - VERSIÓN SIMPLIFICADA
// ============================================

console.log("========================================");
console.log("📥 PARSE UNIFICADO - INICIANDO");
console.log("========================================");

// Obtener el contenido de la respuesta de OpenRouter
let content = "";

try {
    // La respuesta puede venir en diferentes estructuras
    if ($json.choices && $json.choices[0] && $json.choices[0].message) {
        content = $json.choices[0].message.content;
    } else if ($json.content) {
        content = $json.content;
    } else if (typeof $json === 'string') {
        content = $json;
    } else {
        content = JSON.stringify($json);
    }

    console.log("✅ Contenido obtenido, longitud:", content.length);
} catch (e) {
    console.error("❌ Error obteniendo contenido:", e.message);
    content = "";
}

// Obtener datos de mercado del contexto
let contextData = {};
let currentPrice = 1.15305;
let trend = "bullish";

try {
    // Intentar obtener el contexto del nodo anterior
    const prevNode = $node["Agente Unificado"];
    if (prevNode && prevNode.json && prevNode.json.context) {
        contextData = prevNode.json.context;
        const marketData = contextData.market_data || {};
        currentPrice = marketData.technical?.current_price || 1.15305;
        trend = marketData.technical?.trend || "bullish";
    }
} catch (e) {
    console.log("⚠️ No se pudo obtener contexto, usando valores por defecto");
}

console.log(`💰 Precio actual: ${currentPrice}`);
console.log(`📈 Tendencia: ${trend}`);

// ============================================
// EXTRAER DECISIÓN DEL TEXTO
// ============================================

let decision = "hold";
let confidence = 50;

// Buscar palabras clave de decisión
const textLower = content.toLowerCase();

if (textLower.includes("**buy**") || 
    textLower.includes("direction:** buy") ||
    (textLower.includes("buy") && !textLower.includes("sell") && textLower.includes("long"))) {
    decision = "buy";
    confidence = 70;
    console.log("✅ Decisión detectada: BUY");
} else if (textLower.includes("**sell**") || 
           textLower.includes("direction:** sell") ||
           textLower.includes("short")) {
    decision = "sell";
    confidence = 70;
    console.log("✅ Decisión detectada: SELL");
} else if (textLower.includes("hold") || textLower.includes("wait")) {
    decision = "hold";
    confidence = 30;
    console.log("⚠️ Decisión detectada: HOLD");
} else {
    console.log("⚠️ No se detectó decisión clara, usando tendencia");
    if (trend === "bullish") {
        decision = "buy";
        confidence = 55;
    } else if (trend === "bearish") {
        decision = "sell";
        confidence = 55;
    }
}

// ============================================
// EXTRAER NIVELES DE PRECIO
// ============================================

// Función para buscar números en el texto
function extractNumber(text, pattern) {
    const regex = new RegExp(pattern, 'i');
    const match = text.match(regex);
    if (match && match[1]) {
        const num = parseFloat(match[1].replace(',', '.'));
        return isNaN(num) ? null : num;
    }
    return null;
}

// Extraer entry zone
let entryLow = currentPrice * 0.999;
let entryHigh = currentPrice * 1.001;

const entryPatterns = [
    /entry zone[:\s]*[*]*\[([0-9.]+),\s*([0-9.]+)\]/i,
    /entry[:\s]*\[([0-9.]+)[,\s]+([0-9.]+)\]/i,
    /between\s+([0-9.]+)\s+and\s+([0-9.]+)/i,
    /([0-9]+\.[0-9]+)\s*-\s*([0-9]+\.[0-9]+)/i
];

for (const pattern of entryPatterns) {
    const match = content.match(pattern);
    if (match && match[1] && match[2]) {
        const val1 = parseFloat(match[1]);
        const val2 = parseFloat(match[2]);
        if (val1 > 0.9 && val1 < 1.3 && val2 > 0.9 && val2 < 1.3) {
            entryLow = val1;
            entryHigh = val2;
            console.log(`📊 Entry zone encontrada: ${entryLow} - ${entryHigh}`);
            break;
        }
    }
}

// Extraer stop loss
let stopLow = currentPrice * 0.997;
let stopHigh = currentPrice * 1.003;

const stopPatterns = [
    /stop[-\s]*loss[:\s]*[*]*\[([0-9.]+),\s*([0-9.]+)\]/i,
    /stop[:\s]*\[([0-9.]+)[,\s]+([0-9.]+)\]/i,
    /stop[-]loss[:\s]*([0-9.]+)/i
];

for (const pattern of stopPatterns) {
    const match = content.match(pattern);
    if (match) {
        if (match[1] && match[2]) {
            const val1 = parseFloat(match[1]);
            const val2 = parseFloat(match[2]);
            if (val1 > 0.9 && val1 < 1.3 && val2 > 0.9 && val2 < 1.3) {
                stopLow = val1;
                stopHigh = val2;
                console.log(`📊 Stop loss encontrado: ${stopLow} - ${stopHigh}`);
                break;
            }
        } else if (match[1]) {
            const val = parseFloat(match[1]);
            if (val > 0.9 && val < 1.3) {
                if (decision === "buy") {
                    stopLow = val;
                    stopHigh = val + 0.001;
                } else {
                    stopLow = val - 0.001;
                    stopHigh = val;
                }
                console.log(`📊 Stop loss encontrado: ${stopLow} - ${stopHigh}`);
                break;
            }
        }
    }
}

// Extraer take profits
let tp1 = decision === "buy" ? currentPrice * 1.003 : currentPrice * 0.997;
let tp2 = decision === "buy" ? currentPrice * 1.005 : currentPrice * 0.995;

const tp1Patterns = [
    /take[-\s]*profit[-\s]*1[:\s]*[*]*([0-9.]+)/i,
    /tp1[:\s]*([0-9.]+)/i,
    /profit\s+1[:\s]*([0-9.]+)/i
];

for (const pattern of tp1Patterns) {
    const match = content.match(pattern);
    if (match && match[1]) {
        const val = parseFloat(match[1]);
        if (val > 0.9 && val < 1.3) {
            tp1 = val;
            console.log(`📊 TP1 encontrado: ${tp1}`);
            break;
        }
    }
}

const tp2Patterns = [
    /take[-\s]*profit[-\s]*2[:\s]*[*]*([0-9.]+)/i,
    /tp2[:\s]*([0-9.]+)/i,
    /profit\s+2[:\s]*([0-9.]+)/i
];

for (const pattern of tp2Patterns) {
    const match = content.match(pattern);
    if (match && match[1]) {
        const val = parseFloat(match[1]);
        if (val > 0.9 && val < 1.3) {
            tp2 = val;
            console.log(`📊 TP2 encontrado: ${tp2}`);
            break;
        }
    }
}

// Extraer volumen
let volume = 0.04;
const volumeMatch = content.match(/(\d+\.?\d*)\s*(?:standard\s*)?lots?/i);
if (volumeMatch) {
    const vol = parseFloat(volumeMatch[1]);
    if (vol > 0 && vol <= 1) {
        volume = Math.min(0.05, Math.max(0.01, vol));
        console.log(`📊 Volumen encontrado: ${volume} lots`);
    }
}

// Redondear todos los valores
entryLow = Math.round(entryLow * 100000) / 100000;
entryHigh = Math.round(entryHigh * 100000) / 100000;
stopLow = Math.round(stopLow * 100000) / 100000;
stopHigh = Math.round(stopHigh * 100000) / 100000;
tp1 = Math.round(tp1 * 100000) / 100000;
tp2 = Math.round(tp2 * 100000) / 100000;

console.log("========================================");
console.log("📊 DATOS FINALES EXTRACCIÓN:");
console.log(`   Decisión: ${decision.toUpperCase()}`);
console.log(`   Confianza: ${confidence}%`);
console.log(`   Entry: ${entryLow} - ${entryHigh}`);
console.log(`   Stop: ${stopLow} - ${stopHigh}`);
console.log(`   TP1: ${tp1}`);
console.log(`   TP2: ${tp2}`);
